import { Card, CardContent } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import Link from "next/link";

async function getData() {
  const res = await fetch("http://localhost:3000/api/vessels", {
    cache: "no-store",
  });
  return res.json();
}

export default async function AuctionsPage() {
  const vessels = await getData();

  return (
    <div className="p-10 grid md:grid-cols-3 gap-6">
      {vessels.map((v: any) => (
        <Link key={v.id} href={`/vessels/${v.id}`}>
          <Card className="hover:scale-105 transition">
            <img src={v.image} className="h-48 w-full object-cover" />

            <CardContent className="p-4">
              <h2 className="font-bold text-lg">{v.name}</h2>
              <p className="text-blue-600 font-bold">{v.price}</p>
              <Badge>{v.status}</Badge>
            </CardContent>
          </Card>
        </Link>
      ))}
    </div>
  );
}